// 위도/경도 -> 3D 구면 좌표 변환
function latLonToXYZ(lat, lon, r) {
  var latR = lat * Math.PI / 180;
  var lonR = lon * Math.PI / 180;
  return [
    r * Math.cos(latR) * Math.sin(lonR),
    r * Math.sin(latR),
    r * Math.cos(latR) * Math.cos(lonR)
  ];
}
ctx.state.latLonToXYZ = latLonToXYZ;

