  for (var ai2=0; ai2<s.axisLines.length; ai2++) {
    var aL=s.axisLines[ai2];
    lineData.push(aL.points[0][0],aL.points[0][1],aL.points[0][2],aL.color[0],aL.color[1],aL.color[2],aL.color[3],
      aL.points[1][0],aL.points[1][1],aL.points[1][2],aL.color[0],aL.color[1],aL.color[2],aL.color[3]);
    lineVertCount+=2;
  }
}

if (showTrade > 0.5 && s.tradeArcs && s.arcsInitialized) {
  var maxTrade=s.maxTotalTrade, thresholdVal=tradeThreshold*maxTrade, ARC_SEGS=s.arcSegs;
  var arcsDrawn=0, markerCountries={};
  for (var ai=0; ai<s.tradeArcs.length; ai++) {
    var arc=s.tradeArcs[ai];
    if (arc.totalValue<thresholdVal) continue; if (arcsDrawn>=maxArcsToShow) break; if (!arc.pts) continue;
    var col=arc.color, normVol=arc.normalizedVol, arcPts=arc.pts;
    for (var j=0; j<ARC_SEGS; j++) {
      var t=j/ARC_SEGS;
      var pT=(time*pulseSpeed*0.4)%1.0, pT2=(time*pulseSpeed*0.4+0.33)%1.0, pT3=(time*pulseSpeed*0.4+0.66)%1.0;
      var pW=0.07+normVol*0.06;
      var p1=Math.max(0,1-Math.abs(t-pT)/pW), p2=Math.max(0,1-Math.abs(t-pT2)/pW), p3=Math.max(0,1-Math.abs(t-pT3)/pW);
      var pV=Math.max(p1,Math.max(p2,p3)); pV*=pV;
      var glowA=0.08+normVol*0.2+pV*tradeGlow*0.8, bright=0.25+pV*0.75;
      lineData.push(arcPts[j][0],arcPts[j][1],arcPts[j][2],col[0]*bright,col[1]*bright,col[2]*bright,glowA,
        arcPts[j+1][0],arcPts[j+1][1],arcPts[j+1][2],col[0]*bright,col[1]*bright,col[2]*bright,glowA);
      lineVertCount+=2;
    }
    markerCountries[arc.origin]=arc.from; markerCountries[arc.dest]=arc.to; arcsDrawn++;
  }
  var regionColors=s.regionColors, mKeys=Object.keys(markerCountries);
  for (var mi=0; mi<mKeys.length; mi++) {
    var cName=mKeys[mi], pos=markerCountries[cName], mCol=regionColors[cName]||[0.6,0.6,0.6];
    var ms2=0.02, mP=0.7+0.3*Math.sin(time*3.0+mi);
    lineData.push(pos[0]-ms2,pos[1],pos[2],mCol[0]*mP,mCol[1]*mP,mCol[2]*mP,0.9, pos[0]+ms2,pos[1],pos[2],mCol[0]*mP,mCol[1]*mP,mCol[2]*mP,0.9,
      pos[0],pos[1]-ms2,pos[2],mCol[0]*mP,mCol[1]*mP,mCol[2]*mP,0.9, pos[0],pos[1]+ms2,pos[2],mCol[0]*mP,mCol[1]*mP,mCol[2]*mP,0.9,
      pos[0],pos[1],pos[2]-ms2,mCol[0]*mP,mCol[1]*mP,mCol[2]*mP,0.9, pos[0],pos[1],pos[2]+ms2,mCol[0]*mP,mCol[1]*mP,mCol[2]*mP,0.9);
    lineVertCount+=6;
  }
  s._arcsDrawn = arcsDrawn;
}

if (lineVertCount > 0) {
  var lineArr = new Float32Array(lineData);
  gl.useProgram(s.lineProgram); gl.uniformMatrix4fv(s.lineLocs.uViewProj, false, viewProj);
  gl.bindVertexArray(s.lineVao); gl.bindBuffer(gl.ARRAY_BUFFER, s.lineBuf);
  if (lineArr.byteLength > 16*1024*1024) gl.bufferData(gl.ARRAY_BUFFER, lineArr, gl.DYNAMIC_DRAW);
  else gl.bufferSubData(gl.ARRAY_BUFFER, 0, lineArr);
  gl.drawArrays(gl.LINES, 0, lineVertCount); gl.bindVertexArray(null);
}
gl.disable(gl.BLEND); gl.disable(gl.DEPTH_TEST);

if (showLabels > 0.5 && showTrade > 0.5 && s.tradeArcs && s.arcsInitialized && s.labelCanvas) {
  var canW=ctx.canvas.width, canH=ctx.canvas.height;
  if (s.labelCanvas.width!==canW||s.labelCanvas.height!==canH) { s.labelCanvas.width=canW; s.labelCanvas.height=canH; }
  var lctx = s.labelCtx; lctx.clearRect(0,0,canW,canH);
  function project3D(pos,vpMat,w,h) {
    var x=pos[0],y=pos[1],z=pos[2],m=vpMat;
    var cx=m[0]*x+m[4]*y+m[8]*z+m[12], cy=m[1]*x+m[5]*y+m[9]*z+m[13], cw=m[3]*x+m[7]*y+m[11]*z+m[15];
    if (cw<=0.001) return null; return [(cx/cw*0.5+0.5)*w, (1.0-(cy/cw*0.5+0.5))*h];
  }
  var maxTrade=s.maxTotalTrade, thresholdVal=tradeThreshold*maxTrade, regionColors=s.regionColors;
  var labelLimit = Math.min(80, maxArcsToShow); var labelsDrawn = 0;
  for (var ai=0; ai<s.tradeArcs.length && labelsDrawn<labelLimit; ai++) {
    var arc=s.tradeArcs[ai]; if (arc.totalValue<thresholdVal) continue; if (!arc.ctrl) continue;
    var ctrl=arc.ctrl, labelPos=[ctrl[0]*1.06,ctrl[1]*1.06,ctrl[2]*1.06];
    var screenPos=project3D(labelPos,viewProj,canW,canH);
    if (!screenPos) continue; if (screenPos[0]<-50||screenPos[0]>canW+50||screenPos[1]<-50||screenPos[1]>canH+50) continue;
    var col=arc.color, normVol=arc.normalizedVol;
    var fontSize=Math.max(9, Math.min(14, 9+normVol*5));
    lctx.font='bold '+fontSize+'px monospace'; lctx.textAlign='center';
    var r255=Math.round(col[0]*255),g255=Math.round(col[1]*255),b255=Math.round(col[2]*255);
    lctx.fillStyle='rgba('+r255+','+g255+','+b255+',0.9)'; lctx.shadowColor='rgba('+r255+','+g255+','+b255+',0.4)'; lctx.shadowBlur=6;
    lctx.fillText(arc.origin+' \u2192 '+arc.dest, screenPos[0], screenPos[1]);
    lctx.font=(fontSize-2)+'px monospace'; lctx.fillStyle='rgba(200,220,255,0.8)'; lctx.shadowColor='rgba(0,0,0,0.5)'; lctx.shadowBlur=3;
    var valStr; if (arc.totalValue>=1e9) valStr='$'+(arc.totalValue/1e9).toFixed(2)+'B'; else valStr='$'+(arc.totalValue/1e6).toFixed(1)+'M';
    lctx.fillText(valStr+' ('+arc.shipments+' shipments)', screenPos[0], screenPos[1]+fontSize+1);
    lctx.shadowBlur=0; labelsDrawn++;
  }
  if (s.uniqueCountries) {
    var countryTotals={}; var arcLimit2=Math.min(s.tradeArcs.length,maxArcsToShow);
    for (var ci=0;ci<arcLimit2;ci++) { var a=s.tradeArcs[ci]; if(a.totalValue<thresholdVal) continue; countryTotals[a.origin]=(countryTotals[a.origin]||0)+a.totalValue; countryTotals[a.dest]=(countryTotals[a.dest]||0)+a.totalValue; }
    var sortedCountries=Object.keys(countryTotals).sort(function(a,b){return countryTotals[b]-countryTotals[a];});
    var countryCoords=s.countryCoords, latLonToXYZ=s.latLonToXYZ;
    var topN=Math.min(40, sortedCountries.length);
    for (var ci=0;ci<topN;ci++) {
      var cName=sortedCountries[ci], cc=countryCoords[cName]; if(!cc) continue;
      var pos3d=latLonToXYZ(cc.lat,cc.lon,1.06), sp=project3D(pos3d,viewProj,canW,canH);
      if(!sp) continue; if(sp[0]<10||sp[0]>canW-10||sp[1]<10||sp[1]>canH-10) continue;
      var mCol=regionColors[cName]||[0.6,0.6,0.6];
      lctx.font='bold 9px monospace'; lctx.textAlign='center';
      lctx.fillStyle='rgba('+Math.round(mCol[0]*255)+','+Math.round(mCol[1]*255)+','+Math.round(mCol[2]*255)+',0.7)';
      lctx.shadowColor='rgba(0,0,0,0.6)'; lctx.shadowBlur=3;
      lctx.fillText(cName.toUpperCase(), sp[0], sp[1]-8); lctx.shadowBlur=0;
    }
  }
  lctx.font='bold 14px monospace'; lctx.textAlign='left';
  lctx.fillStyle='rgba(180,220,255,0.85)'; lctx.shadowColor='rgba(100,150,255,0.3)'; lctx.shadowBlur=6;
  lctx.fillText('GLOBAL TRADE FLOWS', 20, 30);
  lctx.font='11px monospace'; lctx.fillStyle='rgba(150,180,220,0.7)';
  var infoStr='Feb-Mar 2026 + US Dec 2025 | '+(s.totalShipments||'?')+' records | '+(s.totalPairs||'?')+' routes | showing '+(s._arcsDrawn||0);
  lctx.fillText(infoStr, 20, 48); lctx.shadowBlur=0;
  var legendY=68; lctx.font='10px monospace';
  if (s.tradeArcs && s.tradeArcs.length>0) {
    var grandTotal=0, shown=Math.min(s.tradeArcs.length,maxArcsToShow);
    for (var si=0;si<shown;si++) { if(s.tradeArcs[si].totalValue<thresholdVal) continue; grandTotal+=s.tradeArcs[si].totalValue; }
    lctx.fillStyle='rgba(255,200,100,0.8)';
    var totalStr; if(grandTotal>=1e9) totalStr='$'+(grandTotal/1e9).toFixed(1)+'B'; else totalStr='$'+(grandTotal/1e6).toFixed(0)+'M';
    lctx.fillText('Visible trade volume: '+totalStr, 20, legendY); legendY+=14;
  }
  lctx.fillStyle='rgba(200,200,200,0.6)'; lctx.fillText('Arc color = origin country | Brightness = trade volume', 20, legendY);

  gl.enable(gl.BLEND); gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
  gl.activeTexture(gl.TEXTURE0); gl.bindTexture(gl.TEXTURE_2D, s.labelTex);
  gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL, true);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, s.labelCanvas);
  gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL, false);
  gl.useProgram(s.labelProgram); gl.uniform1i(s.labelLocs.uLabelTex, 0);
  gl.bindVertexArray(s.quadVao); gl.drawArrays(gl.TRIANGLES, 0, 6); gl.bindVertexArray(null);
  gl.disable(gl.BLEND);
}

script.cleanup:
var gl = ctx.gl;
var s = ctx.state;
if (s.atmoProgram) gl.deleteProgram(s.atmoProgram);
if (s.lineProgram) gl.deleteProgram(s.lineProgram);
if (s.labelProgram) gl.deleteProgram(s.labelProgram);
if (s.quadBuf) gl.deleteBuffer(s.quadBuf);
if (s.lineBuf) gl.deleteBuffer(s.lineBuf);
if (s.quadVao) gl.deleteVertexArray(s.quadVao);
if (s.lineVao) gl.deleteVertexArray(s.lineVao);
if (s.earthGLTex) gl.deleteTexture(s.earthGLTex);
if (s.normalGLTex) gl.deleteTexture(s.normalGLTex);
if (s.darkGLTex) gl.deleteTexture(s.darkGLTex);
if (s.labelTex) gl.deleteTexture(s.labelTex);
